                    in 11..15 -> "HIGH"
                    else -> "CRITICAL"
                },
                deadline = assessment.endDate.plusDays(30),
                owner = assessment.assessor,
                asset = asset
            )

            val savedRisk = riskRepository.save(risk)

            log.info("Created risk {} from assessment {} for requirement {}", 
